
import { ref, defineComponent, reactive, toRefs, inject } from "vue";
import { postGrabASingle } from "../../../server/http/api/Amultitasking";

export default defineComponent({
  props: ["rowData", "team"],
  setup(props: any, ctx: any) {
    const visible = ref<boolean>(false);
    const confirmLoading = ref<boolean>(false);
    const init: any = inject("init");
    const formRef = ref();
    const formState = reactive({
      inspector: [],
      recorder: [],
      reviewer: [],
      reportProducer: [],
    });
    const rules = {
      inspector: [
        {
          required: true,
          message: "请输入检测人",
          trigger: "blur",
          type: "array",
        },
      ],
      recorder: [
        {
          required: true,
          message: "请输入记录人",
          trigger: "blur",
          type: "array",
        },
      ],
      reviewer: [
        {
          required: true,
          message: "请输入复核人",
          trigger: "blur",
          type: "array",
        },
      ],
      reportProducer: [
        {
          required: true,
          message: "请输入报告制作人",
          trigger: "blur",
          type: "array",
        },
      ],
    };

    const showModal = (rowData: any) => {
      //console.log(rowData);
      visible.value = true;
    };

    const handleOk = () => {
      formRef.value
        .validate()
        .then(() => {
          confirmLoading.value = true;
          let form = {
            code: props.rowData.taskCode,
            id: props.rowData.taskId,
            inspector: formState.inspector.join(","),
            recorder: formState.recorder.join(","),
            reviewer: formState.reviewer.join(","),
            reportProducer: formState.reportProducer.join(","),
          };
          postGrabASingle(form).then((res: any) => {
            if (res.data.code === 200) {
              init();
            }
            // init
            visible.value = false;
            confirmLoading.value = false;
            formState.inspector = [];
            formState.recorder = [];
            formState.reviewer = [];
            formState.reportProducer = [];
          });
        })
        .catch((error: any) => {
          console.log("error", error);
        });
    };
    return {
      visible,
      confirmLoading,
      showModal,
      handleOk,

      formState,
      formRef,
      rules,
    };
  },
});
