
import { defineComponent, reactive, ref, toRefs } from "vue";

import ReturnTitle from "@/components/OS_component/ReturnTitle.vue";
import Graborders from "@/components/Amultitasking/modal/Graborders.vue";
import Information from "@/components/Amultitasking/modal/Information.vue";
import {
  getTaskDetailInfo,
  getTeamUserName,
} from "../../../../../server/http/api/Amultitasking";
import { useRoute } from "vue-router";
const columns = [
  {
    dataIndex: "checkItemName",
    key: "checkItemName",

    title: "检测项",
    slots: { customRender: "checkItemName" },
  },
  {
    title: "检测方法",
    dataIndex: "methodName",
    key: "methodName",
  },
  {
    title: "检测依据",
    key: "standardName",
    dataIndex: "standardName",
    slots: { customRender: "standardName" },
  },

  {
    title: "单价",
    key: "checkPrice",
    dataIndex: "checkPrice",
    slots: { customRender: "checkPrice" },
  },
  {
    title: "检测样次",
    key: "times",
    dataIndex: "times",
  },
  {
    title: "知识信息",
    key: "action",
    slots: { customRender: "action" },
  },
];
export default defineComponent({
  components: { ReturnTitle, Graborders, Information },
  name: "TaskacceptanceDetail",

  setup() {
    const route: any = useRoute();
    const team = ref();
    // 任务单详情
    const data = reactive({
      sampleDetailList: [],
      taskId: "",
      taskCode: "",
      orderer: "",
      orderTime: "",
      requiredCompletionTime: "",
      cost: "",
      samplingMethod: "",
      checkPurpose: "",
      presentInformation: "",
      fileUrl: "",
    });
    getTaskDetailInfo(route.params.id * 1).then((res: any) => {
      if (res.data.code === 200) {
        Object.assign(data, res.data.data);
        //console.log(data);
      }
    });
    // 获取登入团队
    getTeamUserName().then((res: any) => {
      //console.log(res);
      if (res.data.code === 200) {
        team.value = res.data.data.teamVo.map((item: any) => {
          return { label: item.label, value: `${item.label}&${item.value}` };
        });
      }
    });
    return {
      columns,
      team,
      data,
      ...toRefs(data),
    };
  },
});
