
import { defineComponent, ref } from "vue";
export default defineComponent({
  props: ["detail"],
  setup() {
    const visible = ref<boolean>(false);

    const showModal = (detail: any) => {
      //console.log(detail);
      
      visible.value = true;
    };

    const handleOk = (e: MouseEvent) => {
      //console.log(e);
      visible.value = false;
    };
    return {
      visible,
      showModal,
      handleOk,
    };
  },
});
